export const getRoleColor = (role: PlayerRole) => {
    switch (role) {
        case PlayerRole.BATSMAN: return 'text-blue-400';
        case PlayerRole.FAST_BOWLER: return 'text-red-400';
        case PlayerRole.ALL_ROUNDER: return 'text-emerald-400';
        case PlayerRole.WICKET_KEEPER: return 'text-yellow-400';
        default: return 'text-gray-400';
    }
};

