};

// --- Main Entry ---

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);

  const startNewGame = () => setAppState('TEAM_SELECTION');

  const initializeGame = (teamId: string) => {
    setGameData({
        userTeamId: teamId,
        teams: INITIAL_TEAMS,
        currentSeason: 2026,
        currentFormat: Format.T20
    });
    setAppState('CAREER_HUB');
  };

  return (
    <div className="bg-gray-100 dark:bg-[#020617] min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-white dark:bg-slate-950 border-x border-gray-200 dark:border-slate-800 shadow-2xl overflow-hidden relative flex flex-col">
        {appState === 'MAIN_MENU' && <MainMenu onStart={startNewGame} />}
        {appState === 'TEAM_SELECTION' && <TeamSelection onSelect={initializeGame} />}
        {appState === 'CAREER_HUB' && gameData && <CareerHub gameData={gameData} />}
      </div>
    </div>
  );
};

