export const getCommentary = (runs: number, isOut: boolean, batterName: string, bowlerName: string) => {
    if (isOut) return `OUT! ${batterName} is dismissed by ${bowlerName}!`;
    const texts = ["Defended.", "Single taken.", "Two runs.", "Driven for three!", "FOUR!", "That's five!", "SIX!"];
    return texts[runs] || "No run.";
};

export const getRoleColor = (role: PlayerRole) => {
    switch (role) {
        case PlayerRole.BATSMAN: return 'text-blue-400';
        case PlayerRole.FAST_BOWLER: return 'text-red-400';
        case PlayerRole.ALL_ROUNDER: return 'text-emerald-400';
        case PlayerRole.WICKET_KEEPER: return 'text-yellow-400';
        case PlayerRole.SPIN_BOWLER: return 'text-purple-400';
        default: return 'text-gray-400';
    }
};

export const getRoleFullName = (role: PlayerRole) => {
    switch (role) {
        case PlayerRole.BATSMAN: return 'Batsman';
        case PlayerRole.WICKET_KEEPER: return 'Wicket-Keeper';
        case PlayerRole.ALL_ROUNDER: return 'All-Rounder';
        case PlayerRole.SPIN_BOWLER: return 'Spin Bowler';
        case PlayerRole.FAST_BOWLER: return 'Fast Bowler';
        default: return 'Player';
    }
};

export const getBattingStyleLabel = (style: string) => style === 'A' ? 'Aggressive' : style === 'D' ? 'Defensive' : 'Balanced';
export const BATTING_STYLE_OPTIONS = ['A', 'D', 'N', 'NA'];

export const formatOvers = (balls: number) => {
    const overs = Math.floor(balls / 6);
    const remaining = balls % 6;
    return `${overs}.${remaining}`;
};

export const getPlayerById = (id: string, allPlayers: Player[]): Player => {
    return allPlayers.find(p => p.id === id) || allPlayers[0];
};

export const generateAutoXI = (squad: Player[], format: Format): Player[] => {
    return [...squad].sort((a, b) => (b.battingSkill + b.secondarySkill) - (a.battingSkill + a.secondarySkill)).slice(0, 11);
};

export const getBatterTier = (battingSkill: number) => {
    if (battingSkill >= 80) return 'tier1';
    if (battingSkill >= 65) return 'tier2';
    if (battingSkill >= 50) return 'tier3';
    return 'tier4';
};

export const BATTING_PROFILES = Object.values(Format).reduce((acc, f) => {
    acc[f] = { tier1: { N: { avg: 40, sr: 130 }, A: { avg: 35, sr: 150 }, D: { avg: 45, sr: 100 } }, tier2: { N: { avg: 30, sr: 120 } }, tier3: { N: { avg: 20, sr: 110 } }, tier4: { N: { avg: 10, sr: 90 } } };
    return acc;
}, {} as any);

export const aggregateStats = (player: Player, formats: Format[]): PlayerStats => {
    const total = generateSingleFormatInitialStats();
    formats.forEach(f => {
        const s = player.stats[f];
        if (s) {
            total.matches += s.matches;
            total.runs += s.runs;
            total.wickets += s.wickets;
            if (s.highestScore > total.highestScore) total.highestScore = s.highestScore;
        }
    });
    total.average = total.matches > 0 ? total.runs / total.matches : 0;
    return total;
};

export const calculatePopularityPoints = (result: MatchResult, format: Format, userTeamId: string) => (result.winnerId === userTeamId ? 5 : 1);

export const generateMatchNews = (result: MatchResult, format: string, sponsorship: Sponsorship): NewsArticle => ({
    id: generateId(), headline: `${result.summary}`, date: 'Today', excerpt: `Match result for ${format}`, content: result.summary, type: 'match'
});

export const generatePreMatchNews = (match: Match, gameData: GameData): NewsArticle => ({
    id: generateId(), headline: `Preview: ${match.teamA} vs ${match.teamB}`, date: 'Today', excerpt: 'Big game today.', content: 'The teams are ready.', type: 'match'
});

export const generateLeagueSchedule = (teams: Team[], format: Format): Match[] => {
    const schedule: Match[] = [];
    if (teams.length < 2) return [];
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            schedule.push({ matchNumber: schedule.length + 1, teamA: teams[i].name, teamAId: teams[i].id, vs: 'vs', teamB: teams[j].name, teamBId: teams[j].id, date: `Day ${schedule.length+1}`, group: 'Round-Robin' });
        }
    }
    return schedule;
};

