import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Player, Team, GameData, PlayerRole, Format } from '../types';
import { getRoleColor, getRoleFullName } from '../utils';
import { Icons } from './Icons';
import { MAX_FOREIGN_PLAYERS, MIN_FOREIGN_PLAYERS, MAX_LOCAL_PLAYERS, MIN_LOCAL_PLAYERS, MAX_SQUAD_SIZE, MIN_SQUAD_SIZE } from '../data';

interface AuctionRoomProps {
    gameData: GameData;
    onAuctionComplete: (updatedTeams: Team[]) => void;
}

const STARTING_PURSE = 50.0;

const shuffle = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
};

const AuctionRoom: React.FC<AuctionRoomProps> = ({ gameData, onAuctionComplete }) => {
    const [teams, setTeams] = useState<Team[]>(() => 
        gameData.teams.map(t => ({ ...t, squad: [], purse: STARTING_PURSE }))
    );

    const [activeOverlay, setActiveOverlay] = useState<'none' | 'franchises' | 'pool'>('none');

    const sortedPool = useMemo(() => {
        return shuffle([...gameData.allPlayers]).sort((a, b) => {
            const skillA = Math.max(a.battingSkill, a.secondarySkill);
            const skillB = Math.max(b.battingSkill, b.secondarySkill);
            return skillB - skillA;
        });
    }, [gameData.allPlayers]);

    const [currentPlayerIdx, setCurrentPlayerIdx] = useState(0);
    const [currentBid, setCurrentBid] = useState(0);
    const [highestBidderId, setHighestBidderId] = useState<string | null>(null);
    const [isAuctioning, setIsAuctioning] = useState(false);
    const [biddingLog, setBiddingLog] = useState<string[]>([]);
    const [auctionFinished, setAuctionFinished] = useState(false);

    const currentPlayer = sortedPool[currentPlayerIdx] || null;
    const userTeam = teams.find(t => t.id === gameData.userTeamId);

    const getBasePrice = (player: Player) => {
        const attr = Math.max(player.battingSkill, player.secondarySkill);
        if (attr > 70) return 2.0;
        if (attr >= 60) return 1.0; 
        if (attr >= 50) return 0.5;
        return 0.2;
    };

    const startNextPlayer = useCallback(() => {
        if (auctionFinished) return;

        if (currentPlayerIdx >= sortedPool.length) {
            setAuctionFinished(true);
            return;
        }

        const player = sortedPool[currentPlayerIdx];
        if (!player) {
            setCurrentPlayerIdx(prev => prev + 1);
            return;
        }

        const bp = getBasePrice(player);
        setCurrentBid(bp);
        setHighestBidderId(null);
        setIsAuctioning(true);
        setBiddingLog(prev => [`Lot #${currentPlayerIdx + 1}: ${player.name} up for ${bp.toFixed(2)} Cr`, ...prev.slice(0, 5)]);
    }, [currentPlayerIdx, sortedPool, auctionFinished]);

    const handleUserBid = () => {
        if (!userTeam || !isAuctioning || !currentPlayer) return;

        if (currentPlayer.isForeign && userTeam.squad.filter(p => p.isForeign).length >= MAX_FOREIGN_PLAYERS) {
            setBiddingLog(prev => [`Foreign limit reached!`, ...prev.slice(0, 5)]);
            return;
        }
        if (!currentPlayer.isForeign && userTeam.squad.filter(p => !p.isForeign).length >= MAX_LOCAL_PLAYERS) {
            setBiddingLog(prev => [`Pakistani limit reached!`, ...prev.slice(0, 5)]);
            return;
        }

        const nextBid = Number((currentBid + 0.1).toFixed(2));
        if (userTeam.purse < nextBid) return;

        setCurrentBid(nextBid);
        setHighestBidderId(userTeam.id);
        setBiddingLog(prev => [`${userTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
    };

    const skipPlayer = () => {
        setIsAuctioning(false);
        setBiddingLog(prev => [`Passed: ${currentPlayer?.name}`, ...prev]);
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 200);
    };

    const autoAuctionRemaining = () => {
        setIsAuctioning(false);
        setAuctionFinished(true);
    };

    useEffect(() => {
        if (!isAuctioning || !currentPlayer || auctionFinished) return;

        const timer = setTimeout(() => {
            const otherTeams = teams.filter(t => t.id !== highestBidderId && t.id !== gameData.userTeamId);
            const biddingTeam = otherTeams.find(t => {
                const isForeign = currentPlayer.isForeign;
                const foreignCount = t.squad.filter(p => p.isForeign).length;
                const localCount = t.squad.filter(p => !p.isForeign).length;

                if (isForeign && foreignCount >= MAX_FOREIGN_PLAYERS) return false;
                if (!isForeign && localCount >= MAX_LOCAL_PLAYERS) return false;

                const valuation = (Math.max(currentPlayer.battingSkill, currentPlayer.secondarySkill) / 60) * 8.0;
                return t.purse >= (currentBid + 0.1) && (currentBid + 0.1) <= valuation;
            });

            if (biddingTeam) {
                const nextBid = Number((currentBid + 0.1).toFixed(2));
                setCurrentBid(nextBid);
                setHighestBidderId(biddingTeam.id);
                setBiddingLog(prev => [`${biddingTeam.name} bids ${nextBid.toFixed(2)} Cr!`, ...prev.slice(0, 5)]);
            } else if (highestBidderId) {
                sellPlayer();
            } else {
                unsoldPlayer();
            }
        }, 600 + Math.random() * 400);

        return () => clearTimeout(timer);
    }, [isAuctioning, currentBid, highestBidderId, currentPlayer, teams]);

    const sellPlayer = () => {
        setIsAuctioning(false);
        const winner = teams.find(t => t.id === highestBidderId);
        if (winner && currentPlayer) {
            setTeams(prev => prev.map(t => {
                if (t.id === winner.id) {
                    return { ...t, purse: Number((t.purse - currentBid).toFixed(2)), squad: [...t.squad, currentPlayer] };
                }
                return t;
            }));
            setBiddingLog(prev => [`SOLD! ${currentPlayer.name} to ${winner.name}`, ...prev]);
        }
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 600);
    };

    const unsoldPlayer = () => {
        setIsAuctioning(false);
        setBiddingLog(prev => [`UNSOLD: ${currentPlayer.name}`, ...prev]);
        setTimeout(() => setCurrentPlayerIdx(prev => prev + 1), 600);
    };

    useEffect(() => {
        if (!isAuctioning && !auctionFinished) startNextPlayer();
    }, [currentPlayerIdx, isAuctioning, auctionFinished, startNextPlayer]);

    const finishAuction = () => {
        const soldPlayerIds = new Set(teams.flatMap(t => t.squad.map(p => p.id)));
        let pool = shuffle(gameData.allPlayers.filter(p => !soldPlayerIds.has(p.id)));

        const finalTeams = teams.map(team => {
            let squad = [...team.squad];
            let purse = team.purse;

            const fillFromPool = (isForeign: boolean, target: number) => {
                let count = squad.filter(p => p.isForeign === isForeign).length;
                while (count < target && pool.length > 0) {
                    const idx = pool.findIndex(p => p.isForeign === isForeign);
                    if (idx === -1) break;
                    const p = pool.splice(idx, 1)[0];
                    squad.push(p);
                    count++;
                    purse = Math.max(0, purse - 0.2);
                }
            };

            // Enforce Min Limits
            fillFromPool(true, MIN_FOREIGN_PLAYERS);
            fillFromPool(false, MIN_LOCAL_PLAYERS);

            // Fill to reached min squad size if not there
            while (squad.length < MIN_SQUAD_SIZE && pool.length > 0) {
                const isForeign = squad.filter(p => p.isForeign).length < MAX_FOREIGN_PLAYERS;
                const idx = pool.findIndex(p => p.isForeign === isForeign || !isForeign);
                if (idx === -1) break;
                const p = pool.splice(idx, 1)[0];
                squad.push(p);
                purse = Math.max(0, purse - 0.1);
            }

            return { ...team, squad, purse };
        });

        onAuctionComplete(finalTeams);
    };

    return (
        <div className="h-full flex flex-col bg-[#020617] text-white font-sans overflow-hidden relative">
            {activeOverlay === 'franchises' && (
                <div className="absolute inset-0 z-50 bg-slate-950 flex flex-col p-4 animate-in slide-in-from-bottom duration-300">
                    <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4">
                        <h2 className="text-xl font-black italic tracking-tighter uppercase">ROSTERS</h2>
                        <button onClick={() => setActiveOverlay('none')} className="bg-slate-800 p-2 rounded-full"><Icons.X /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto space-y-6">
                        {teams.map(team => (
                            <div key={team.id} className={`p-4 rounded-2xl border ${team.id === gameData.userTeamId ? 'bg-slate-900 border-teal-500 shadow-lg' : 'bg-slate-900/40 border-slate-800'}`}>
                                <div className="flex justify-between mb-3">
                                    <h4 className="font-black uppercase tracking-tighter text-sm">{team.name}</h4>
                                    <span className="text-sm font-black text-teal-400">{team.purse.toFixed(2)} Cr</span>
                                </div>
                                <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-[10px]">
                                    <div>F: {team.squad.filter(p => p.isForeign).length} / {MAX_FOREIGN_PLAYERS}</div>
                                    <div>L: {team.squad.filter(p => !p.isForeign).length} / {MAX_LOCAL_PLAYERS}</div>
                                    <div className="col-span-2 text-zinc-500">Total: {team.squad.length} / {MAX_SQUAD_SIZE}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <div className="bg-[#0f172a] p-4 pt-10 border-b border-slate-800 flex justify-between items-center shadow-2xl z-10">
                <div className="bg-yellow-500 text-black px-2 py-0.5 rounded font-black text-xs skew-x-[-12deg]">LIVE DRAFT</div>
                <div className="text-right">
                    <span className="text-xl font-black text-teal-400">{userTeam?.purse?.toFixed(2) || '0.00'} Cr</span>
                    <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest leading-none">Your Purse</p>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 flex flex-col">
                {!auctionFinished ? (
                    <>
                        {currentPlayer ? (
                            <div className="bg-slate-900/80 rounded-[2rem] border border-slate-800 shadow-2xl p-6 relative flex flex-col">
                                <div className="flex justify-between items-start mb-6">
                                    <div className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${getRoleColor(currentPlayer.role)} bg-opacity-20 border border-current`}>
                                        {getRoleFullName(currentPlayer.role)} {currentPlayer.isForeign ? '✈️' : '🏠'}
                                    </div>
                                    <div className="text-[10px] text-slate-600 font-bold uppercase">{currentPlayer.nationality}</div>
                                </div>

                                <div className="text-center mb-8">
                                    <h2 className="text-4xl font-black italic uppercase tracking-tighter mb-4">{currentPlayer.name}</h2>
                                    <div className="flex justify-center gap-6">
                                        <div><p className="text-[10px] text-slate-500 font-bold uppercase">Batting</p><p className="text-2xl font-black text-blue-400">{currentPlayer.battingSkill}</p></div>
                                        <div><p className="text-[10px] text-slate-500 font-bold uppercase">Bowling</p><p className="text-2xl font-black text-red-400">{currentPlayer.secondarySkill}</p></div>
                                    </div>
                                </div>

                                <div className="bg-black/40 rounded-2xl p-4 mb-8 text-center border border-white/5">
                                    <span className="text-[10px] text-slate-500 uppercase font-black block mb-2">CURRENT BID</span>
                                    <div className="text-6xl font-black text-yellow-400 tabular-nums">{currentBid.toFixed(2)} <span className="text-2xl">Cr</span></div>
                                    <div className="mt-1 text-xs font-bold text-slate-400 uppercase tracking-widest truncate">
                                        {highestBidderId ? `Leading: ${teams.find(t => t.id === highestBidderId)?.name}` : 'Awaiting Bids'}
                                    </div>
                                </div>

                                <button 
                                    onClick={handleUserBid}
                                    disabled={!isAuctioning || highestBidderId === userTeam?.id || (userTeam?.purse || 0) < (currentBid + 0.1)}
                                    className={`w-full py-5 rounded-2xl font-black text-2xl italic uppercase tracking-tighter shadow-2xl transition-all ${highestBidderId === userTeam?.id ? 'bg-emerald-600' : 'bg-teal-500'} disabled:opacity-20`}
                                >
                                    Bid ({(currentBid + 0.1).toFixed(2)})
                                </button>
                                <div className="grid grid-cols-2 gap-3 mt-4">
                                    <button onClick={skipPlayer} className="bg-slate-800 py-3 rounded-xl text-[10px] font-black uppercase">Pass</button>
                                    <button onClick={autoAuctionRemaining} className="bg-red-950 py-3 rounded-xl text-[10px] font-black uppercase text-red-300">Fast Draft</button>
                                </div>
                            </div>
                        ) : null}

                        <div className="mt-auto pt-6">
                            <button onClick={() => setActiveOverlay('franchises')} className="w-full bg-slate-800 py-3 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2">
                                <Icons.Podium /> All Rosters
                            </button>
                            <div className="bg-black p-3 rounded-xl h-24 overflow-y-auto border border-white/5 font-mono text-[9px] mt-4">
                                {biddingLog.map((log, i) => <div key={i} className="mb-1 text-slate-500">{log}</div>)}
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center px-4">
                        <div className="text-8xl mb-8">🏏</div>
                        <h2 className="text-4xl font-black italic uppercase text-teal-400">Draft Finished</h2>
                        <p className="text-slate-400 my-6 text-sm">Squads are finalized following the 16-18 player rule.</p>
                        <button onClick={finishAuction} className="w-full bg-teal-500 py-6 rounded-[2rem] text-xl font-black italic uppercase shadow-xl hover:bg-teal-400">
                            Enter Career
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

