import AuctionRoom from './AuctionRoom';

interface CareerHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
    onResetGame: () => void;
    theme: 'light' | 'dark';
    setTheme: (theme: 'light' | 'dark') => void;
    saveGame: () => void;
    loadGame: () => void;
    showFeedback: (message: string, type?: 'success' | 'error') => void;
}

const BottomNavBar = ({ activeScreen, setScreen }: { activeScreen: CareerScreen, setScreen: (screen: CareerScreen) => void }) => {
    const navItems = [
        { name: 'HOME', screen: 'DASHBOARD' as CareerScreen, icon: Icons.Home },
        { name: 'LEAGUES', screen: 'LEAGUES' as CareerScreen, icon: Icons.Podium },
        { name: 'STATS', screen: 'STATS' as CareerScreen, icon: Icons.ChartPie },
        { name: 'SETTINGS', screen: 'SETTINGS' as CareerScreen, icon: Icons.Settings },
    ];
    return (
        <nav className="bg-gray-100/80 dark:bg-[#101F1F] border-t border-gray-300/50 dark:border-gray-700/50 flex justify-around items-center h-[90px] pb-4 backdrop-blur-sm">
            {navItems.map(item => (
                <button
                    key={item.name}
                    onClick={() => setScreen(item.screen)}
                    className={`flex flex-col items-center justify-center space-y-1 w-1/4 pt-2 transition-colors duration-200 ${activeScreen === item.screen ? 'text-teal-500' : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'}`}
                >
                    <item.icon />
                    <span className="text-[10px] font-bold tracking-wider">{item.name}</span>
                </button>
            ))}
        </nav>
    );
};

const CareerHub: React.FC<CareerHubProps> = ({ gameData, setGameData, onResetGame, theme, setTheme, saveGame, loadGame, showFeedback }) => {
    const [screen, setScreen] = useState<CareerScreen>('DASHBOARD');
    const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
    const [playerProfileFormat, setPlayerProfileFormat] = useState<Format>(gameData.currentFormat);
    const [selectedMatchResult, setSelectedMatchResult] = useState<MatchResult | null>(null);
    const [forwardSimResults, setForwardSimResults] = useState<MatchResult[]>([]);

    const { runSimulationForCurrentFormat, updateStatsFromMatch } = useSimulation(gameData, setGameData);

    useEffect(() => {
        if (gameData && (!gameData.sponsorships || !gameData.popularity || !gameData.news)) {
             setGameData(prev => {
                 if (!prev) return null;
                 return {
                     ...prev,
                     popularity: prev.popularity ?? 50,
                     sponsorships: prev.sponsorships ?? INITIAL_SPONSORSHIPS,
                     news: prev.news ?? INITIAL_NEWS
                 };
             });
        }
    }, [gameData, setGameData]);

    const userTeam = useMemo(() => {
        return gameData.teams.find(t => t.id === gameData.userTeamId) || gameData.teams[0];
    }, [gameData]);

    useEffect(() => {
        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];

        if (schedule && currentMatchIndex >= schedule.length) {
            const awardExists = gameData.awardsHistory.some(a => a.season === gameData.currentSeason && a.format === gameData.currentFormat);

            if (!awardExists) {
                const formatStats = new Map();
                gameData.teams.forEach(team => team.squad.forEach(player => {
                    const p = getPlayerById(player.id, gameData.allPlayers);
                    if (p) {
                       formatStats.set(p.id, { runs: p.stats[gameData.currentFormat].runs, wickets: p.stats[gameData.currentFormat].wickets, teamName: team.name, playerName: p.name })
                    }
                }));

                const sortedBatters = [...formatStats.entries()].sort((a, b) => b[1].runs - a[1].runs);
                const sortedBowlers = [...formatStats.entries()].sort((a, b) => b[1].wickets - a[1].wickets);

                const finalMatchNumber = schedule[schedule.length-1].matchNumber;
                const lastMatchResult = gameData.matchResults[gameData.currentFormat].find(r => r.matchNumber === finalMatchNumber);
                const winnerTeam = gameData.teams.find(t => t.id === lastMatchResult?.winnerId);

                const newAward = { 
                    season: gameData.currentSeason, 
                    format: gameData.currentFormat, 
                    winnerTeamId: winnerTeam?.id || '', 
                    winnerTeamName: winnerTeam?.name || 'N/A', 
                    bestBatter: { playerId: sortedBatters[0]?.[0] || '', playerName: sortedBatters[0]?.[1].playerName || 'N/A', teamName: sortedBatters[0]?.[1].teamName || 'N/A', runs: sortedBatters[0]?.[1].runs || 0 }, 
                    bestBowler: { playerId: sortedBowlers[0]?.[0] || '', playerName: sortedBowlers[0]?.[1].playerName || 'N/A', teamName: sortedBowlers[0]?.[1].teamName || 'N/A', wickets: sortedBowlers[0]?.[1].wickets || 0 } 
                };

                setGameData(prev => prev ? { ...prev, awardsHistory: [...prev.awardsHistory, newAward] } : null);
                setScreen('END_OF_FORMAT');
            }
        }
    }, [gameData.currentMatchIndex, gameData.currentFormat, gameData.currentSeason, gameData.awardsHistory, gameData.teams, gameData.allPlayers, gameData.matchResults, gameData.schedule, setGameData]);

    const handleUpdatePlayer = (updatedPlayer: Player) => {
        setGameData(prevData => {
            if (!prevData) return null;
            const newAllPlayers = prevData.allPlayers.map(p => p.id === updatedPlayer.id ? updatedPlayer : p);
            return { ...prevData, allPlayers: newAllPlayers };
        });
    };

    const handleCreatePlayer = (newPlayer: Player) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return { ...prevData, allPlayers: [...prevData.allPlayers, newPlayer] };
        });
    };

    const handleUpdateCaptain = (teamId: string, format: Format, playerId: string) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return {
                ...prevData,
                teams: prevData.teams.map(t => {
                    if (t.id === teamId) {
                        return { ...t, captains: { ...t.captains, [format]: playerId } };
                    }
                    return t;
                })
            };
        });
        showFeedback("Captain updated!");
    };

    const handleUpdatePlayingXI = (teamId: string, format: Format, newXI: string[]) => {
        setGameData(prevData => {
            if (!prevData) return null;
            const teamXIs = prevData.playingXIs[teamId] || {};
            return {
                ...prevData,
                playingXIs: {
                    ...prevData.playingXIs,
                    [teamId]: {
                        ...teamXIs,
                        [format]: newXI
                    }
                }
            };
        });
    };

    const handleForwardDay = () => {
        if (!userTeam) return;
        let currentData = { ...gameData };
        let matchIndex = currentData.currentMatchIndex[currentData.currentFormat];
        let schedule = currentData.schedule[currentData.currentFormat];
        const results: MatchResult[] = [];
        const newNewsItems: NewsArticle[] = [];

        for(let i=0; i<5; i++) {
            if (matchIndex + i < schedule.length) {
                const m = schedule[matchIndex+i];
                if (m.teamA === userTeam.name || m.teamB === userTeam.name) {
                    newNewsItems.push(generatePreMatchNews(m, currentData));
                    break;
                }
            }
        }

        let simulatedCount = 0;
        const maxSimulations = 8;

        while (matchIndex < schedule.length && simulatedCount < maxSimulations) {
            let matchToSim = JSON.parse(JSON.stringify(schedule[matchIndex]));

            if (matchToSim.group !== 'Round-Robin') {
                const standings = currentData.standings[currentData.currentFormat];
                const getTeamName = (pos: number) => standings[pos - 1]?.teamName;
                const resolvePlaceholder = (placeholder: string) => {
                    if (['1st', '2nd', '3rd', '4th'].includes(placeholder)) return getTeamName(parseInt(placeholder[0]));
                    return placeholder;
                };
                matchToSim.teamA = resolvePlaceholder(matchToSim.teamA) || 'TBD';
                matchToSim.teamB = resolvePlaceholder(matchToSim.teamB) || 'TBD';
                if (matchToSim.teamA === 'TBD' || matchToSim.teamB === 'TBD') break; 
            }

            const isUserTeamMatch = matchToSim.teamA === userTeam.name || matchToSim.teamB === userTeam.name;
            if (isUserTeamMatch) break;

            const result = runSimulationForCurrentFormat(matchToSim, currentData);
            currentData = updateStatsFromMatch(result, currentData.currentFormat, currentData);
            currentData.currentMatchIndex[currentData.currentFormat]++; 
            results.push(result);
            simulatedCount++;
            matchIndex++;
        }

        if (results.length > 0) {
            setForwardSimResults(results);
            setGameData(currentData); 
            setScreen('FORWARD_RESULTS');
        } else {
             showFeedback("Your match is next!", "success");
        }
    };

    const handlePlayMatch = () => {
        if (!userTeam) return;
        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];
        if (currentMatchIndex >= schedule.length) return;

        let matchToSim = JSON.parse(JSON.stringify(schedule[currentMatchIndex]));
        if (matchToSim.teamA === 'TBD' || matchToSim.teamB === 'TBD') {
            showFeedback("Opponent not yet decided.", "error");
            return;
        }

        const isUserTeamMatch = matchToSim.teamA === userTeam.name || matchToSim.teamB === userTeam.name;
        if (isUserTeamMatch) setScreen('LIVE_MATCH');
        else {
             const result = runSimulationForCurrentFormat(matchToSim, gameData);
             const updatedData = updateStatsFromMatch(result, gameData.currentFormat, gameData);
             updatedData.currentMatchIndex[gameData.currentFormat]++;
             setGameData(updatedData);
             setSelectedMatchResult(result);
             setScreen('MATCH_RESULT');
        }
    };

    const handleFormatChange = useCallback((newFormat: Format) => {
        setGameData(prev => prev ? ({ ...prev, currentFormat: newFormat }) : null);
        setScreen('DASHBOARD');
    }, [setGameData]);

    const handleEndOfSeason = useCallback((retainedPlayers: Player[]) => {
        setGameData((prevData: GameData | null) => {
            if (!prevData) return null;
            const newTeams = prevData.teams.map(t => {
                if (t.id === prevData.userTeamId) return { ...t, squad: retainedPlayers, purse: 50.0 - retainedPlayers.length };
                return { ...t, squad: [], purse: 50.0 };
            });
            return {
                ...prevData,
                currentSeason: prevData.currentSeason + 1,
                currentFormat: Format.T20,
                currentMatchIndex: { [Format.T20]: 0, [Format.ODI]: 0, [Format.FIRST_CLASS]: 0 },
                matchResults: { [Format.T20]: [], [Format.ODI]: [], [Format.FIRST_CLASS]: [] },
                teams: newTeams
            };
        });
        setScreen('AUCTION_ROOM');
    }, [setGameData]);

    const renderScreen = () => {
        const commonProps = { gameData, userTeam, setGameData, setScreen, showFeedback };
        switch(screen) {
            case 'DASHBOARD': return <Dashboard {...commonProps} handlePlayMatch={handlePlayMatch} handleForwardDay={handleForwardDay} />;
            case 'LEAGUES': return <Standings gameData={gameData} />; 
            case 'LINEUPS': return <Lineups {...commonProps} handleUpdatePlayingXI={handleUpdatePlayingXI} handleUpdateCaptain={handleUpdateCaptain} />;
            case 'STATS': return <Stats gameData={gameData} viewPlayerProfile={(p, f) => { setSelectedPlayer(p); setPlayerProfileFormat(f); setScreen('PLAYER_PROFILE'); }} />;
            case 'SETTINGS': return <Settings onResetGame={onResetGame} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} />;
            case 'MATCH_RESULT': return <MatchResultScreen result={selectedMatchResult} onBack={() => setScreen('DASHBOARD')} userTeamId={gameData.userTeamId} />;
            case 'LIVE_MATCH': return <LiveMatchScreen match={gameData.schedule[gameData.currentFormat][gameData.currentMatchIndex[gameData.currentFormat]]} gameData={gameData} onMatchComplete={r => { updateStatsFromMatch(r, gameData.currentFormat, gameData); setScreen('MATCH_RESULT'); }} onExit={() => setScreen('DASHBOARD')} />;
            case 'END_OF_FORMAT': return <EndOfFormatScreen gameData={gameData} handleFormatChange={handleFormatChange} handleEndSeason={handleEndOfSeason} />;
            case 'PLAYER_PROFILE': return <PlayerProfile player={selectedPlayer} onBack={() => setScreen('STATS')} initialFormat={playerProfileFormat} />;
            case 'AUCTION_ROOM': return <AuctionRoom gameData={gameData} onAuctionComplete={(teams) => { setGameData(prev => prev ? { ...prev, teams } : null); setScreen('DASHBOARD'); }} />;
            default: return <Dashboard {...commonProps} handlePlayMatch={handlePlayMatch} handleForwardDay={handleForwardDay} />;
        }
    }

    return (
        <div className="flex flex-col h-full">
            <main className="flex-grow overflow-y-auto">{renderScreen()}</main>
            <BottomNavBar activeScreen={screen} setScreen={setScreen} />
        </div>
    );
};

export default CareerHub;

import React, { useState, useEffect, useMemo } from 'react';
import { GameData, Team, Format, Player } from '../types';
import { Icons } from './Icons';
import { getRoleColor, generateAutoXI } from '../utils';

interface LineupsProps {
    gameData: GameData;
    userTeam: Team | null;
    handleUpdatePlayingXI: (teamId: string, format: Format, newXI: string[]) => void;
    handleUpdateCaptain: (teamId: string, format: Format, playerId: string) => void;
    showFeedback: (message: string, type?: 'success' | 'error') => void;
}

const Lineups: React.FC<LineupsProps> = ({ gameData, userTeam, handleUpdatePlayingXI, handleUpdateCaptain, showFeedback }) => {
    const [selectedTeamId, setSelectedTeamId] = useState(userTeam?.id || '');
    const selectedTeam = useMemo(() => gameData.teams.find(t => t.id === selectedTeamId), [gameData.teams, selectedTeamId]);
    const [selectedFormat, setSelectedFormat] = useState<Format>(gameData.currentFormat);
    const [playingXI, setPlayingXI] = useState<Player[]>([]);
    const [bench, setBench] = useState<Player[]>([]);
    const [playerToSwap, setPlayerToSwap] = useState<Player | null>(null);

    useEffect(() => {
        if (!selectedTeam) return;
        const xiIds = gameData.playingXIs[selectedTeam.id]?.[selectedFormat] || [];
        let xiPlayers = xiIds.map(id => selectedTeam.squad.find(p => p.id === id)).filter(Boolean) as Player[];
        if (xiPlayers.length !== 11) {
            xiPlayers = generateAutoXI(selectedTeam.squad, selectedFormat);
            handleUpdatePlayingXI(selectedTeam.id, selectedFormat, xiPlayers.map(p => p.id));
        }
        setPlayingXI(xiPlayers);
        setBench(selectedTeam.squad.filter(p => !xiPlayers.some(xp => xp.id === p.id)));
    }, [selectedTeam, selectedFormat]);

    const completeSwap = (playerFromBench: Player) => {
        if (!playerToSwap) return;
        const newXI = playingXI.map(p => p.id === playerToSwap.id ? playerFromBench : p);
        const foreignCount = newXI.filter(p => p.isForeign).length;

        if (foreignCount > 4) {
            showFeedback("Max 4 foreign players allowed in XI", "error");
            return;
        }
        if (foreignCount < 2 && selectedTeam?.squad.filter(p => p.isForeign).length >= 2) {
            showFeedback("Min 2 foreign players required in XI", "error");
            return;
        }

        handleUpdatePlayingXI(selectedTeam!.id, selectedFormat, newXI.map(p => p.id));
        setPlayerToSwap(null);
        showFeedback("Swap completed", "success");
    };

    return (
        <div className="p-4 flex flex-col h-full">
            <h2 className="text-xl font-bold mb-4">Lineup Manager</h2>
            <div className="space-y-4">
                <select value={selectedFormat} onChange={e => setSelectedFormat(e.target.value as Format)} className="w-full p-2 rounded bg-slate-800">
                    {Object.values(Format).map(f => <option key={f} value={f}>{f}</option>)}
                </select>
                <div className="bg-slate-900 p-3 rounded">
                    <h3 className="font-bold text-teal-400 mb-2">Playing XI ({playingXI.filter(p => p.isForeign).length} Foreign)</h3>
                    <div className="space-y-1">
                        {playingXI.map(p => (
                            <div key={p.id} onClick={() => setPlayerToSwap(p)} className={`p-2 rounded flex justify-between cursor-pointer ${playerToSwap?.id === p.id ? 'bg-teal-900' : 'bg-slate-800'}`}>
                                <span>{p.name} {p.isForeign ? '✈️' : ''}</span>
                                <span className={getRoleColor(p.role)}>{p.role}</span>
                            </div>
                        ))}
                    </div>
                </div>
                <div className="bg-slate-900 p-3 rounded flex-grow">
                    <h3 className="font-bold text-gray-400 mb-2">Bench</h3>
                    <div className="space-y-1">
                        {bench.map(p => (
                            <div key={p.id} onClick={() => playerToSwap && completeSwap(p)} className="p-2 rounded bg-slate-800 flex justify-between cursor-pointer">
                                <span>{p.name} {p.isForeign ? '✈️' : ''}</span>
                                <span className={getRoleColor(p.role)}>{p.role}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Lineups;

export enum Format {
    T20 = 'Premier T20 League',
    ODI = 'Premier One-Day Cup',
    FIRST_CLASS = 'Premier First-Class Shield',
    // Fix: Added missing tournament formats to resolve Property 'DEVELOPMENT_T20' etc. does not exist on type 'typeof Format' errors
    DEVELOPMENT_T20 = 'Development T20 Cup',
    DEVELOPMENT_ODI = 'Development List-A Cup',
    DEVELOPMENT_FIRST_CLASS = 'Development First-Class Cup',
    RISE_T20 = 'Rise T20 Cup',
    RISE_ODI = 'Rise List-A Cup',
    RISE_FIRST_CLASS = 'Rise First-Class Cup'
}

export enum PlayerRole {
    BATSMAN = 'BT',
    WICKET_KEEPER = 'WK',
    ALL_ROUNDER = 'AR',
    SPIN_BOWLER = 'SB',
    FAST_BOWLER = 'BL',
}

export type BattingStyle = 'A' | 'D' | 'N' | 'NA';
export type Strategy = 'defensive' | 'balanced' | 'attacking';
export type AppState = 'MAIN_MENU' | 'TEAM_SELECTION' | 'AUCTION' | 'CAREER_HUB';
export type CareerScreen = 'DASHBOARD' | 'LEAGUES' | 'LINEUPS' | 'EDITOR' | 'NEWS' | 'STATS' | 'SETTINGS' | 'PLAYER_PROFILE' | 'MATCH_RESULT' | 'FORWARD_RESULTS' | 'AWARDS_RECORDS' | 'TRANSFERS' | 'END_OF_FORMAT' | 'COMPARISON' | 'SCHEDULE' | 'LIVE_MATCH' | 'ASSISTANT' | 'SPONSOR_ROOM' | 'CUSTOMIZATION' | 'SELECT_PLAYER_FOR_COMPARISON_SLOT_1' | 'SELECT_PLAYER_FOR_COMPARISON_SLOT_2' | 'AUCTION_ROOM' | 'RETENTION' | 'PLAYER_DATABASE';

export interface PlayerStats {
    matches: number; runs: number; highestScore: number; average: number; strikeRate: number; ballsFaced: number; dismissals: number;
    hundreds: number; fifties: number; thirties: number; fours: number; sixes: number; fastestFifty: number; fastestHundred: number;
    wickets: number; economy: number; bestBowling: string; bestBowlingWickets: number; bestBowlingRuns: number; bowlingAverage: number;
    ballsBowled: number; runsConceded: number; threeWicketHauls: number; fiveWicketHauls: number; catches: number; runOuts: number;
    manOfTheMatchAwards: number;
}

export interface Player {
    id: string; name: string; nationality: string; role: PlayerRole; battingSkill: number; secondarySkill: number;
    style: BattingStyle; isOpener: boolean; isForeign: boolean; teamName?: string;
    customProfiles?: { [key in Format]?: { avg: number; sr: number } };
    stats: Record<Format, PlayerStats>;
}

export interface Team {
    id: string; name: string; squad: Player[]; captains: { [key in Format]?: string };
    purse: number; 
}

export interface TeamData {
    id: string; name: string; homeGround: string; logo: string; isDevelopmentTeam?: boolean;
}

export interface Ground {
    name: string; code: string; pitch: string; dimensions?: string; weather?: 'Sunny' | 'Overcast' | 'Rainy' | 'Humid' | 'Dry';
    boundarySize?: 'Small' | 'Medium' | 'Large'; outfieldSpeed?: 'Fast' | 'Medium' | 'Slow' | 'Lightning'; capacity?: number;
}

export interface Match {
    matchNumber: number | string; teamA: string; teamAId?: string; vs: string; teamB: string; teamBId?: string; date: string; group: 'Round-Robin' | 'Semi-Finals' | 'Final';
}

export interface Inning {
    teamId: string; teamName: string; score: number; wickets: number; overs: string; batting: BattingPerformance[]; bowling: BowlingPerformance[]; extras: number; recentBalls?: string[];
}

export interface BattingPerformance {
    playerId: string; playerName: string; runs: number; balls: number; fours: number; sixes: number; isOut: boolean; dismissalText: string; dismissal: { type: 'not out' | 'bowled' | 'caught'; bowlerId: string; fielderId?: string; }; ballsToFifty?: number; ballsToHundred?: number;
}

export interface BowlingPerformance {
    playerId: string; playerName: string; overs: string; maidens: number; runsConceded: number; wickets: number; ballsBowled: number;
}

export interface MatchResult {
    matchNumber: number | string; winnerId: string | null; loserId: string | null; isDraw?: boolean; summary: string; firstInning: Inning; secondInning: Inning; thirdInning?: Inning; fourthInning?: Inning; manOfTheMatch: { playerId: string; playerName: string; teamId: string; summary: string; }; tossWinnerId?: string; tossDecision?: 'bat' | 'bowl';
}

export interface Standing {
    teamId: string; teamName: string; played: number; won: number; lost: number; drawn: number; points: number; netRunRate: number; runsFor?: number; runsAgainst?: number;
}

export interface NewsArticle {
    id: string; headline: string; date: string; excerpt: string; content: string; type?: 'match' | 'transfer' | 'league' | 'squad';
}

export interface Award {
    season: number; format: Format; winnerTeamId: string; winnerTeamName: string;
    bestBatter: { playerId: string, playerName: string, teamName: string, runs: number };
    bestBowler: { playerId: string, playerName: string, teamName: string, wickets: number };
}

export interface ScoreLimits { maxRuns?: number; maxWickets?: number; }
export type InningLimits = { [key: number]: ScoreLimits; };

export interface BatterVsBowlerRecord { batterId: string; batterName: string; bowlerId: string; bowlerName: string; runs: number; balls: number; dismissals: number; }
export interface TeamVsTeamRecord { teamAId: string; teamBId: string; teamAName: string; teamBName: string; matches: number; teamAWins: number; }
export interface PlayerVsTeamRecord { playerId: string; playerName: string; playerRole: PlayerRole; vsTeamId: string; vsTeamName: string; runs: number; balls: number; dismissals: number; wickets: number; runsConceded: number; ballsBowled: number; }
export interface PromotionRecord { season: number; promotedTeamId: string; promotedTeamName: string; relegatedTeamId: string; relegatedTeamName: string; }

export interface Sponsorship { sponsorName: string; tournamentName: string; logoColor: string; tournamentLogo?: string; tvChannel?: string; tvLogo?: string; }
export interface Brand { name: string; color: string; style: string; logo: string; }
export interface TVChannel { id: string; name: string; logo: string; color: string; minPopularity: number; tier: 'Premium' | 'Standard' | 'Budget'; }

export interface GameData {
    userTeamId: string; teams: Team[]; grounds: Ground[]; allTeamsData: TeamData[]; allPlayers: Player[]; schedule: Record<Format, Match[]>; currentMatchIndex: Record<Format, number>; standings: Record<Format, Standing[]>; matchResults: Record<Format, MatchResult[]>; playingXIs: Record<string, Partial<Record<Format, string[]>>>; currentSeason: number; currentFormat: Format; awardsHistory: Award[]; records: { batterVsBowler: BatterVsBowlerRecord[]; teamVsTeam: TeamVsTeamRecord[]; playerVsTeam: PlayerVsTeamRecord[]; }; promotionHistory: PromotionRecord[]; popularity: number; sponsorships: Record<Format, Sponsorship>; news: NewsArticle[]; activeMatch: LiveMatchState | null; scoreLimits?: Record<string, Partial<Record<Format, InningLimits>>>; availableBrands?: Brand[]; availableTVChannels?: TVChannel[];
    settings: {
        isDoubleRoundRobin: boolean;
    };
}

export interface LiveMatchState {
    status: 'toss' | 'ready' | 'inprogress' | 'inning_break' | 'completed'; match: Match; currentInningIndex: number; innings: Inning[]; target: number | null; currentBatters: { strikerId: string; nonStrikerId: string }; currentBowlerId: string; recentBalls: string[]; commentary: string[]; battingTeam: Team; bowlingTeam: Team; requiredRunRate: number; currentPartnership: { runs: number, balls: number }; fallOfWickets: { score: number, wicket: number, over: string, player: string }[]; waitingFor: 'openers' | 'batter' | 'bowler' | 'batter_arrival' | 'bowler_change' | null; strategies: { batting: Strategy; bowling: Strategy; }; autoPlayType: 'regular' | 'inning' | 'match' | null; tossWinnerId: string | null; tossDecision: 'bat' | 'bowl' | null;
}

export interface Message { id: string; text: string; sender: 'user' | 'model' | 'bot'; timestamp?: Date; }
